import React from 'react';
import './Navigation.css';

const Navigation = ({ onNavigate, activePage }) => {
  return (
    <nav className="navbar">
      <div className="nav-inner">
        <a href="#home" className="nav-logo" onClick={(e) => {
          e.preventDefault();
          onNavigate('home');
        }}>
          <div className="nav-logo-symbol">🕉</div>
          <div className="nav-logo-text">
            Shree Ram Janaki<br/>Mandir
          </div>
        </a>
        <ul className="nav-links">
          <li>
            <a href="#home" onClick={(e) => {
              e.preventDefault();
              onNavigate('home');
            }} className={activePage === 'home' ? 'active' : ''}>
              Home
            </a>
          </li>
          <li>
            <a href="#about" onClick={(e) => {
              e.preventDefault();
              onNavigate('about');
            }} className={activePage === 'about' ? 'active' : ''}>
              Our Story
            </a>
          </li>
          <li>
            <a href="#members" onClick={(e) => {
              e.preventDefault();
              onNavigate('members');
            }} className={activePage === 'members' ? 'active' : ''}>
              Members
            </a>
          </li>
          <li>
            <a href="#photos" onClick={(e) => {
              e.preventDefault();
              onNavigate('photos');
            }} className={activePage === 'photos' ? 'active' : ''}>
              Photos
            </a>
          </li>
          <li>
            <a href="#contact" onClick={(e) => {
              e.preventDefault();
              onNavigate('contact');
            }} className={activePage === 'contact' ? 'active' : ''}>
              Contact Us
            </a>
          </li>
        </ul>
      </div>
    </nav>
  );
};

export default Navigation;
